const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const secret = body.internal_secret || '';
const expected = process.env.INTERNAL_EMAIL_SECRET || '';
if (!expected || secret !== expected) return { json: { _unauthorized: true, error: 'internal secret required' } };
if (!body.lead_id || !body.client_id || !body.script) return { json: { _empty: true, error: 'lead_id, client_id, script required' } };
return { json: {
  _authorized: true,
  lead_id: body.lead_id,
  client_id: body.client_id,
  script: String(body.script).slice(0, 4000),
  decision_id: body.decision_id || null,
  agent_action_id: body.agent_action_id || null
} };

const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : rows;
const phone = row && row.phone;
if (!phone) return { json: { _no_phone: true, error: 'lead has no phone' } };
const ctx = $('Validate').item.json;
return { json: Object.assign({}, ctx, { to_phone: phone.replace(/[^+0-9]/g, '') }) };

const ctx = $('Compose').item.json;
const resp = $input.item.json || {};
const callId = resp.id || (resp.call && resp.call.id) || null;
if (!callId) return { json: { _failed: true, error: (resp.error || resp.message || 'no_call_id') } };
return { json: { call_id: callId, ctx: ctx } };
